
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';

interface FloatingActionWidgetProps {
  onEnquiry?: () => void;
}

export default function FloatingActionWidget({ onEnquiry }: FloatingActionWidgetProps) {
  const [open, setOpen] = useState(false);
  const navigate = useNavigate();

  const handleTalkWithUs = () => {
    const btn = document.querySelector('#vapi-widget-floating-button') as HTMLElement | null;
    if (btn) btn.click();
    setOpen(false);
  };

  const handleApplyNow = () => {
    navigate('/application');
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setOpen(false);
  };

  const handleEnquiry = () => {
    if (onEnquiry) onEnquiry();
    setOpen(false);
  };

  const actions = [
    {
      label: 'Talk with Us',
      icon: 'ri-customer-service-2-line',
      color: 'bg-slate-800 hover:bg-slate-900 text-white',
      onClick: handleTalkWithUs,
    },
    {
      label: 'Apply Now',
      icon: 'ri-file-add-line',
      color: 'bg-sky-600 hover:bg-sky-700 text-white',
      onClick: handleApplyNow,
    },
    {
      label: 'Enquiry Now',
      icon: 'ri-question-answer-line',
      color: 'bg-orange-500 hover:bg-orange-600 text-white',
      onClick: handleEnquiry,
    },
  ];

  return (
    <div className="fixed right-0 top-1/2 -translate-y-1/2 z-[90] flex flex-col items-end gap-2">
      {/* Expanded action buttons */}
      <div
        className={`flex flex-col items-end gap-2 transition-all duration-300 ${
          open ? 'opacity-100 translate-x-0 pointer-events-auto' : 'opacity-0 translate-x-8 pointer-events-none'
        }`}
      >
        {actions.map((action) => (
          <button
            key={action.label}
            onClick={action.onClick}
            className={`flex items-center gap-2 px-4 py-2.5 rounded-l-full shadow-lg text-sm font-semibold whitespace-nowrap cursor-pointer transition-all duration-200 hover:pr-6 ${action.color}`}
          >
            <i className={`${action.icon} text-base`}></i>
            {action.label}
          </button>
        ))}
      </div>

      {/* Toggle button */}
      <button
        onClick={() => setOpen(!open)}
        title={open ? 'Close' : 'Quick Actions'}
        className={`w-12 h-12 flex items-center justify-center rounded-l-full shadow-xl cursor-pointer transition-all duration-300 whitespace-nowrap ${
          open
            ? 'bg-slate-700 text-white hover:bg-slate-800'
            : 'bg-[#003366] text-white hover:bg-[#004488]'
        }`}
      >
        <i className={`text-xl transition-transform duration-300 ${open ? 'ri-close-line rotate-90' : 'ri-apps-2-line'}`}></i>
      </button>
    </div>
  );
}
