import { useEffect, useState, useRef } from "react";

import img1 from "../../../public/images/img1.png";
import img2 from "../../../public/images/img2.jpeg";
import img3 from "../../../public/images/img3.jpeg";
import img4 from "../../../public/images/img4.jpeg";
import img5 from "../../../public/images/img5.jpeg";
import img6 from "../../../public/images/img6.jpeg";

const images = [img1, img2, img3, img4, img5, img6];

export default function Hero() {
  const [current, setCurrent] = useState(0);
  const [fade, setFade] = useState(true);
  const [navHeight, setNavHeight] = useState(160);
  const rafRef = useRef<number | null>(null);

  // Dynamically measure actual navbar + ticker height
  const measureNav = () => {
    const ticker = document.getElementById('announcements-ticker');
    const navbar = document.querySelector('header');
    let h = 0;
    if (ticker) h += ticker.getBoundingClientRect().height;
    if (navbar) h += navbar.getBoundingClientRect().height;
    if (h > 0) setNavHeight(Math.ceil(h));
  };

  useEffect(() => {
    // Measure after render
    rafRef.current = requestAnimationFrame(() => {
      measureNav();
    });
    window.addEventListener('resize', measureNav);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
      window.removeEventListener('resize', measureNav);
    };
  }, []);

  useEffect(() => {
    const interval = setInterval(() => {
      setFade(false);
      setTimeout(() => {
        setCurrent(prev => (prev + 1) % images.length);
        setFade(true);
      }, 600);
    }, 4500);
    return () => clearInterval(interval);
  }, []);

  const scrollToSection = (id: string) => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: 'smooth' });
  };

  const goTo = (i: number) => {
    setFade(false);
    setTimeout(() => { setCurrent(i); setFade(true); }, 300);
  };

  return (
    <section style={{
      position: 'relative',
      width: '100%',
      height: `calc(100vh - ${navHeight}px)`,
      marginTop: `${navHeight}px`,
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'flex-end',
      overflow: 'hidden',
    }}>

      {/* Slideshow image */}
      <img
        key={current}
        src={images[current]}
        alt="DMI Campus"
        style={{
          position: 'absolute',
          inset: 0,
          width: '100%',
          height: '100%',
          objectFit: 'cover',
          objectPosition: 'center',
          opacity: fade ? 1 : 0,
          transition: 'opacity 0.6s ease-in-out',
          filter: 'brightness(1.08) saturate(1.1)',
          zIndex: 0,
        }}
      />

      {/* Gradient overlay */}
      <div style={{
        position: 'absolute', inset: 0, zIndex: 1,
        background: 'linear-gradient(to bottom, rgba(0,0,0,0) 50%, rgba(0,0,0,0.5) 100%)',
      }} />

      {/* Buttons + dots */}
      <div style={{
        position: 'relative', zIndex: 2,
        display: 'flex', flexDirection: 'column', alignItems: 'center',
        paddingBottom: 'clamp(50px, 8vh, 90px)',
        gap: '18px',
      }}>
        <div style={{
          display: 'flex',
          flexWrap: 'wrap',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '14px',
          width: '100%',
          padding: '0 20px',
          maxWidth: '560px',
        }}>
          <button
            onClick={() => scrollToSection('admissions')}
            style={{
              flex: '1 1 200px',
              background: 'linear-gradient(135deg, #0ea5e9, #2563eb)',
              boxShadow: '0 0 28px rgba(14,165,233,0.55), 0 4px 16px rgba(0,0,0,0.25)',
              border: '2px solid rgba(255,255,255,0.3)',
              color: 'white',
              padding: '15px 28px',
              borderRadius: '16px',
              fontSize: 'clamp(15px, 4vw, 19px)',
              fontWeight: 900,
              cursor: 'pointer',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
              whiteSpace: 'nowrap',
            }}
          >
            <i className="ri-edit-box-line"></i>Apply Now
          </button>

          <button
            onClick={() => scrollToSection('virtual-tour')}
            style={{
              flex: '1 1 200px',
              background: 'rgba(255,255,255,0.15)',
              backdropFilter: 'blur(12px)',
              border: '2px solid rgba(255,255,255,0.6)',
              boxShadow: '0 4px 20px rgba(0,0,0,0.2)',
              color: 'white',
              padding: '15px 28px',
              borderRadius: '16px',
              fontSize: 'clamp(15px, 4vw, 19px)',
              fontWeight: 900,
              cursor: 'pointer',
              display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px',
              whiteSpace: 'nowrap',
            }}
          >
            <i className="ri-video-line"></i>Virtual Tour
          </button>
        </div>

        {/* Dots */}
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          {images.map((_, i) => (
            <button key={i} onClick={() => goTo(i)} style={{
              width: i === current ? '28px' : '10px',
              height: '10px', borderRadius: '5px',
              border: 'none', cursor: 'pointer', padding: 0,
              background: i === current ? '#38bdf8' : 'rgba(255,255,255,0.6)',
              boxShadow: i === current ? '0 0 10px #38bdf8' : 'none',
              transition: 'all 0.35s ease',
            }} />
          ))}
        </div>
      </div>

      {/* Scroll arrow */}
      <div style={{
        position: 'absolute', bottom: '1rem',
        left: '50%', transform: 'translateX(-50%)',
        zIndex: 3, animation: 'heroBounce 2s infinite',
      }}>
        <div style={{
          width: '40px', height: '40px', borderRadius: '50%',
          background: 'rgba(255,255,255,0.2)', backdropFilter: 'blur(8px)',
          border: '2px solid rgba(255,255,255,0.5)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}>
          <i className="ri-arrow-down-line" style={{ color: 'white', fontSize: '18px' }}></i>
        </div>
      </div>

      <style>{`
        @keyframes heroBounce {
          0%, 100% { transform: translateX(-50%) translateY(0); }
          50%       { transform: translateX(-50%) translateY(-8px); }
        }
      `}</style>
    </section>
  );
}